var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이 공간에 있는 대부분의 사람들은 과거, 이 고래에게 잡아먹힌 사람들이에요.","JPN":"ここにいるほとんどの人は、このクジラに食べられてしまった人たちです。","ENG":"The majority of the people here are people who have been eaten by the whale in the past.","TWN":"這個空間裡的大多數人，都是過去被這條鯨魚所吞噬的人。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇다는 건…… 죽은 사람들의 기억을 뽑아다가 보고 있다는 거예요?","JPN":"ということは……死んでしまった人たちの記憶を、抜き取って見ているということなんですか？","ENG":"Then does that mean... that it's extracting memories from the dead and watching them?","TWN":"這樣的話……它是在讀取死人的記憶嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"침식체가 이러는 이유가 뭐죠?","JPN":"どうして侵食体がそんなことをするんですか？","ENG":"Why is the C.O. even doing this?","TWN":"侵蝕體這麼做的理由是什麼？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"<color=#ffd34c>완전해지기 위해서</color>예요.","JPN":"<color=#ffd34c>完全になるため</color>です。","ENG":"<color=#ffd34c>To become complete.</color>","TWN":"要<color=#ffd34c>變得更加完整</color>。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"자신이 삼킨 자들의 기억을 계속해서 되풀이하며 자신의 자아를 유지하는 거죠.","JPN":"自分が飲み込んだ人たちの記憶を、何度も繰り返し見ることで、自分の自我を保とうとしている。","ENG":"It's replaying the memories of those whom it swallowed to maintain its self-awareness.","TWN":"不斷重複被吞噬者的記憶，以維持自我。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"원하는 이상향에 도달하기 위해서.","JPN":"自分を理想の姿に近づけるために。","ENG":"Until it reaches its desired ideal.","TWN":"為了……達到理想的彼岸。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으헥! 갑자기 총알이 날아왔어요! 이거 맞으면 위험한 거 맞죠?","JPN":"うわっ！　いきなり銃弾が飛んできました！　これ、当たったらまずいんでしたよね？","ENG":"Yikes! A bullet just flew past me! It'll be dangerous if I get hit by it, right?","TWN":"呃呃！突然有子彈飛過來！被打中會很危險吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"다치진 않겠지만, 저들이 우릴 인식할 거예요.","JPN":"怪我は負いませんが、向こうに認知されてしまいます。","ENG":"You won't get hurt, but they will know we're here.","TWN":"雖然不會受傷，但他們會注意到我們的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"제가 몇 번이고 확인한 내용이거든요…….","JPN":"私が何度もそれを体験しています……","ENG":"I've confirmed it several times already...","TWN":"這是我多次確認過的內容……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어? 저 사람들은……?","JPN":"あれ？　あの人たちは……？","ENG":"Huh? It's them again...","TWN":"嗯？她們是……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"학회의 규모는?","JPN":"学会の勢力はどのくらいだ？","ENG":"How big is the Society?","TWN":"學會的規模是？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이미 도시 곳곳에 잠복해 있었어요. 본인들도 의식에 휘말릴 생각인 것 같습니다.","JPN":"すでに都市のあちこちに潜んでいます。自分自身までも儀式に使うつもりのようです。","ENG":"They are already lurking around the city. I think they are planning to voluntarily get caught in the ritual.","TWN":"已經潛伏在城市各處，我認為他們自己也打算加入這場儀式。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이들의 목적은 아직 파악되지 않았습니다만, 최대한 많은 수의 제물을 확보하는 것을 계획한 것이 아닐지…….\xA0","JPN":"彼らの目的はいまだ把握できておりません。おそらくできるだけ多くの生贄を確保することではないでしょうか……\xA0","ENG":"Their objective is still unknown, but I assume they are trying to secure as many sacrificial offers as possible...\xA0","TWN":"其目的尚未明確，有可能是計畫盡可能多地獲取祭物……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……의식을 막으러 출동한 저희까지 포함해서 말입니다.","JPN":"……儀式を阻止しにきた、私たちもその数に含まれていると思います。","ENG":"...including us, who were sent here to stop it.","TWN":"……包括我們這些來阻止儀式的人在內。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"현재 학회는 저희가 진입한 입구를 포함해 도시 주변을 모두 봉쇄했습니다.","JPN":"現在、学会は私たちが突入した入口を含む、都市周辺全体を封鎖しています。","ENG":"Currently, the Society has blocked off the entire city entrances, including the one we used.","TWN":"目前學會已經封鎖整個城市入口，包括我們進入的入口。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리까지 계산에 넣은 행동이란 말이군. 작전이 유출된 건가?","JPN":"我々も計画の一部というわけか。作戦が流出していたのか？","ENG":"So they knew that we were coming. Was our operation leaked?","TWN":"意思就是連我們也都算在他們的計畫之內。難道是作戰計畫外洩嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……내부에 배신자가 있다는 뜻일까요?","JPN":"……内部に裏切り者がいるということでしょうか？","ENG":"...Are you saying that there is a traitor among our ranks?","TWN":"……是說內部有叛徒嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"확신할 수 없다. 변수가 발생한 원인을 지금 파악하기엔 시간이 촉박하다.","JPN":"断言はできん。今はこうなってしまった原因追及をしている暇はない。","ENG":"We can't be sure. But there is no time to figure out the cause of the variable.","TWN":"現在還不能確定。時間緊迫，無法查明發生變數的原因。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이번 작전은 너무 위험해. 필요한 인원만 남기고 후퇴한 뒤 지원을 요청한다.","JPN":"今回の作戦は危険すぎる。最低限の人員だけを残して、残りは退却し、支援要請を行う。","ENG":"This operation is too risky. Fall back, leaving only the minimum number of personnel and call for backup.","TWN":"這次作戰太危險了。只留下必要的人手，撤退後請求支援。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만…… 분명 모든 가능성을 검토했어요. 인과율 계산이 어긋났다는 것은…….","JPN":"しかし……あらゆる可能性は検証済みです。因果律計算が狂ったということは……","ENG":"But... we've already checked every possibility. If the causality calculation is off, then...","TWN":"但是……我已經檢查過所有的可能性。如果因果率計算出錯……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리는 우선 사람들을 구한다. 의식을 저지하는 건 나중이야.","JPN":"我々は人命を救う。儀式の阻止はそのあとだ。","ENG":"We rescue the people first. Let's worry about stopping the ritual after.","TWN":"重點是先救人，阻止儀式是後面的事。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"차출할 인원을 제외하고는 모두 퇴각하도록.","JPN":"残る人員を選別し、それ以外は全員退却せよ。","ENG":"Everyone except those selected to stay should retreat.","TWN":"除必要人員，其他人全部撤退。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"퇴각한 인원들은 포위망을 뚫고 카멜롯에 지원을 요청해라.","JPN":"退却する隊員は包囲網を突破し、キャメロットに支援要請をしに向かえ。","ENG":"The retreating personnel should break through the siege and call Camelot for backup.","TWN":"撤退的人員在突破包圍網後，立即請求卡梅羅的支援。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"남은 인원들은 나와 함께 민간인들의 대피를 돕는다.","JPN":"ここに残る者は、私とともに民間人の避難を手伝う。","ENG":"Those remaining will help me evacuate the civilians.","TWN":"剩下的人跟我一起幫助平民撤離。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOL_VARUNA_NULL_NPC","text":{"KOREA":"알겠습니다!","JPN":"了解しました！","ENG":"Yes, ma'am!","TWN":"是！長官！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L49_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우, 우와아…… 박력이 대단하네요.","JPN":"う、うわあ……すごい迫力。","ENG":"W-whoa... she's so cool.","TWN":"哇，哇喔…真是氣勢驚人。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"근데…… 저 사람만 굉장히 흐리게 보여요.","JPN":"でも……あの人、なんだか姿がよく見えませんね。","ENG":"But... that person is the only one that's blurry.","TWN":"但是……那個人看起來非常模糊。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이목구비는커녕 사람인지만 겨우 알아보겠네.","JPN":"顔の形もよくわからないし、人だというのがやっとわかる程度です。","ENG":"I can barely tell that she's human.","TWN":"只能勉強看出是個人，五官根本看不清楚。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 그 사람 옆에 있는 건 당신이잖아요?","JPN":"それに、その隣にいるのは、あなた？","ENG":"And the person next to her is you?","TWN":"而且，站在那個人旁邊的不就是你嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"……네. 저예요.","JPN":"……はい、私です。","ENG":"...Yes. It's me.","TWN":"……對，是我。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"에리두보다 더 오래전 일이라면…… 지나간 시간이…….","JPN":"エリドゥ事件より昔のことということは……かなり昔の……","ENG":"If it's something that happened way before Eridu... then it must be...","TWN":"如果那是比埃里都更久以前的事……已經是……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"진짜로 침식체는…… 아니시죠?","JPN":"本当に侵食体じゃ……ないんですよね？","ENG":"You're not a C.O... are you?","TWN":"你真的不是……侵蝕體吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 다행인지 불행인지, 침식체가 되진 않았네요.","JPN":"あはは、良かったと言っていいのか、侵食体にはなりませんでしたね。","ENG":"Ah hah hah. Not sure if it's a good or a bad thing, but I haven't become a C.O.","TWN":"呵呵喝，不知道是幸運還是不幸，總之沒有變成侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"또 다시 주변이……?","JPN":"また周りが……？","ENG":"The surroundings are changing again...?","TWN":"場景又轉換……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저 사람들은 저희를 보고 있는 것 같죠?","JPN":"あの人たち、こっちを見ているような……？","ENG":"Are they looking at us?","TWN":"那些人好像在看著我們，對吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아니면 우리가 서 있는 자리에 뭐가 있다거나…….","JPN":"それとも、私たちが立っている場所に何かが……","ENG":"Or is there something where we're stand–","TWN":"難道我們站的地方有什麼東西……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"위험해요!","JPN":"危ない！","ENG":"Watch out!","TWN":"危險！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"히이익! 고, 공격했어! 저건 진짜잖아요! 치, 침식체로 변했잖아!","JPN":"ひいいっ！　こ、攻撃してきました！　あれは、本物！　しかも侵食体に化けたし！","ENG":"Eeeek! Th-they attacked us! They were real! And just turned into C.O.s!","TWN":"呃！來真的欸！目標是我們！它們是侵蝕體啦！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아무래도 저희를 인식한 모양이에요.","JPN":"どうやら私たちを認知してしまったようです。","ENG":"I think they've noticed us.","TWN":"看來它們認出我們了。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"적어도 단순한 불순물로 판단한 것 같아 다행이라고 할까…….","JPN":"単に紛れ込んだ不純物程度に思ってくれたみたいで、よかったというべきでしょうか……","ENG":"Luckily, they think that we're just some impurities...","TWN":"只是把我們當作普通的雜質來處理，也算是不幸中的萬幸吧……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이걸로 왜 저들의 눈에 띄면 안 되는지 잘 아시겠죠?","JPN":"どうして彼らの注意を引いてはいけないのか、これでよくわかりましたね？","ENG":"Now do you understand why we shouldn't attract their attention?","TWN":"現在你知道為什麼不能被它們發現了吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무슨 교육 방송하는 것처럼 말하지 말라고요!","JPN":"教育番組のお姉さんみたいな言い方はやめてください！","ENG":"Don't say it like it's some beginner's class for dummies!","TWN":"你以為現在是在做兒童節目嗎！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"혹시나 해서 물어보는 건데, 침식체를 상대해본 경험은 있으세요?","JPN":"一応聞いておきますが、侵食体との戦闘経験はありますか？","ENG":"I'm asking just in case, but do you have any experience fighting C.O.s?","TWN":"以防萬一問一下，你有對付過侵蝕體的經驗嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망치는 거라면 자신 있습니다…….","JPN":"逃げることなら自信があります……","ENG":"I'm good at running away from them...","TWN":"如果是逃跑的話，我很擅長……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"괜찮아요. 그럼 제 곁에 꼭 붙어 계세요.","JPN":"大丈夫です。では、私の近くから離れないようにしてください。","ENG":"That's fine. Just stay close to me then, okay?","TWN":"沒關係，那你要一定要跟緊我。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"길은 제가 뚫도록 하겠습니다!","JPN":"ルートは私が確保しますので！","ENG":"I'll lead the way!","TWN":"我來開路！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};